#define ll long long
ll n,m,w;
ll c[10005],d[10005],fa[10005],mw[10005],v[10005];
ll dp[5004],money[10005],value[10005];
bool vis[10005];
void init(ll x){
    for(ll i=1;i<=x;i++)fa[i]=i;
}
int find(ll x){
    if(fa[x]==x)return x;
    return fa[x]=find(fa[x]);
}
void join(ll x,ll y){
    x=find(x);
    y=find(y);
    if(x==y)return;
    fa[x]=y;

}
bool isSame(ll x,ll y){
    return find(x)==find(y);
}
int main(){
    cin>>n>>m>>w;
    init(n);
    for(ll i=1;i<=n;i++){
        cin>>c[i]>>d[i];
    }
    for(ll i=1;i<=m;i++){
        ll u,v;
        cin>>u>>v;
        join(u,v);
    }
    for(ll i=1;i<=n;i++){
        ll root = find(i);
        vis[root] = true;
        mw[root] += c[i];
        v[root] += d[i];
    }
    ll cnt=0;
    for(ll i=1;i<=n;i++){
        if(vis[i]){
            money[cnt] = mw[i];
            value[cnt++] = v[i];
        }
    }
    for(ll i=0;i<=cnt;i++){
        for(ll j=w;j>=money[i];j--){
            dp[j]=max(dp[j],dp[j-money[i]]+value[i]);
        }
