#define ll long long
ll dp[120][120][120];
ll n,col[120],w,ans;
ll f(ll l,ll r,ll k){
    if(l>r)return 0;
    if(dp[l][r][k]!=-1)return dp[l][r][k];
    ll ans=INT_MAX;
    if(k+1>=w){
        ans=f(l+1,r,0);
    }else{
        ans=f(l,r,k+1)+1;
    }
    for(ll i=l+1;i<=r;i++){
        if(col[l]==col[i]){
            ans=min(ans,f(l+1,i-1,0)+f(i,r,k+1));
        }
    }
    dp[l][r][k]=ans;
    return ans;
}
int main(){
    memset(dp,-1,sizeof(dp));
    cin>>n>>w;
    for(ll i=1;i<=n;i++)cin>>col[i];
    cout<<f(1,n,0)<<endl;
    return 0;
}

