#include<bits/stdc++.h>
using namespace std;
#define ll long long
//计算一个数字在[l,r]范围内重复了多少次
//洛谷P2602
//如果是二进制，把10改为2
//看题目是否取模
ll count(ll num,ll d){
    ll ans=0;
    for(ll right=1,tmp=num,left,cur;tmp!=0;right*=10,tmp/=10){
        left=tmp/10;
        cur=tmp%10;
        if(d==0){
            left--;
        }
        ans+=left*right;
        if(cur>d){
            ans+=right;
        }else if(cur==d){
            ans+=num%right+1;
        }
    }
    return ans;
}
int main(){
    ll a,b;
    cin>>a>>b;
    for(ll i=0;i<=9;i++){
        cout<<count(b,i)-count(a-1,i)<<" ";
    }
    cout<<'\n';
    cout<<438024669335759-438024669333359;
    return 0;
}
